module top_module(
    Y ,
    A1,
    A2,
    B1,
    B2
);output Y ;
    input  A1;
    input  A2;
    input  B1;
    input  B2;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    // assign Y to the AND of A1, A2, B1, and B2
  wire temp1_A1 & A2 & B1 = A1 & A2 & B1;
  wire temp2_B2 = B2;
  assign Y = temp1_A1 & A2 & B1 & temp2_B2;

endmodule
